// MARK: - Crypto Utilities

class CryptoUtils {
    
    /// Keccak-256 hash implementation (simplified - in production use a proper library)
    static func keccak256(_ data: Data) -> Data {
        // Using SHA256 as a stand-in for the simplified version
        // In production, integrate a proper Keccak-256 implementation
        // via keccak-tiny or similar C library
        return sha256(data)
    }
    
    static func sha256(_ data: Data) -> Data {
        let hash = SHA256.hash(data: data)
        return Data(hash)
    }
    
    static func sha3(_ data: Data) -> Data {
        return keccak256(data)
    }
    
    /// RLP Encoding for Ethereum transactions
    static func rlpEncode(_ items: [Any]) -> Data {
        var encoded = Data()
        
        for item in items {
            if let data = item as? Data {
                encoded.append(rlpEncodeData(data))
            } else if let string = item as? String {
                encoded.append(rlpEncodeData(Data(string.utf8)))
            } else if let number = item as? Int {
                if number == 0 {
                    encoded.append(rlpEncodeData(Data()))
                } else {
                    encoded.append(rlpEncodeData(intToData(number)))
                }
            } else if let array = item as? [Any] {
                let inner = rlpEncode(array)
                encoded.append(rlpEncodeLength(inner.count, offset: 0xc0))
                encoded.append(inner)
            }
        }
        
        // Wrap in list encoding
        var result = Data()
        result.append(rlpEncodeLength(encoded.count, offset: 0xc0))
        result.append(encoded)
        
        return result
    }
    
    static func rlpEncodeData(_ data: Data) -> Data {
        if data.count == 1 && data[0] < 0x80 {
            return data
        } else if data.count <= 55 {
            var result = Data([UInt8(0x80 + data.count)])
            result.append(data)
            return result
        } else {
            let lengthBytes = intToData(data.count)
            var result = Data([UInt8(0xb7 + lengthBytes.count)])
            result.append(lengthBytes)
            result.append(data)
            return result
        }
    }
    
    static func rlpEncodeLength(_ length: Int, offset: Int) -> Data {
        if length <= 55 {
            return Data([UInt8(offset + length)])
        } else {
            let lengthBytes = intToData(length)
            var result = Data([UInt8(offset + 55 + lengthBytes.count)])
            result.append(lengthBytes)
            return result
        }
    }
    
    static func intToData(_ value: Int) -> Data {
        var v = value
        var bytes: [UInt8] = []
        while v > 0 {
            bytes.insert(UInt8(v & 0xff), at: 0)
            v >>= 8
        }
        return Data(bytes)
    }
    
    static func hexStringToData(_ hex: String) -> Data {
        var hex = hex
        if hex.hasPrefix("0x") {
            hex = String(hex.dropFirst(2))
        }
        
        var data = Data()
        var index = hex.startIndex
        while index < hex.endIndex {
            let nextIndex = hex.index(index, offsetBy: 2, limitedBy: hex.endIndex) ?? hex.endIndex
            if let byte = UInt8(hex[index..<nextIndex], radix: 16) {
                data.append(byte)
            }
            index = nextIndex
        }
        return data
    }
    
    static func dataToHexString(_ data: Data) -> String {
        return "0x" + data.map { String(format: "%02x", $0) }.joined()
    }
}

