// MARK: - Transaction Signing Service

class TransactionSigningService {
    static let shared = TransactionSigningService()
    
    private init() {}
    
    func signTransaction(_ unsignedTx: UnsignedTransaction, withPrivateKey privateKeyData: Data) throws -> SignedTransaction {
        // Encode transaction for signing (EIP-155)
        let toData = CryptoUtils.hexStringToData(unsignedTx.to)
        let amountWei = weiFromEther(unsignedTx.amount)
        let feeWei = weiFromEther(unsignedTx.fee)
        
        let txFields: [Any] = [
            unsignedTx.nonce,
            feeWei,
            21000, // gas limit for simple transfer
            toData,
            amountWei,
            Data(), // data field (empty for simple transfer)
            unsignedTx.chainId,
            0,
            0
        ]
        
        let encodedTx = CryptoUtils.rlpEncode(txFields)
        let txHash = CryptoUtils.keccak256(encodedTx)
        
        // Sign using P256 (in production, use secp256k1)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: txHash)
        let signatureData = signature.rawRepresentation
        
        // Split signature into r, s, v
        let r = signatureData.prefix(32)
        let s = signatureData.suffix(from: 32).prefix(32)
        let v = UInt8(unsignedTx.chainId * 2 + 35)
        
        let txSignature = TransactionSignature(r: Data(r), s: Data(s), v: v)
        
        // Create signed transaction
        let signedFields: [Any] = [
            unsignedTx.nonce,
            feeWei,
            21000,
            toData,
            amountWei,
            Data(),
            Int(v),
            r,
            s
        ]
        
        let signedEncoded = CryptoUtils.rlpEncode(signedFields)
        let signedHash = CryptoUtils.dataToHexString(CryptoUtils.keccak256(signedEncoded))
        
        return SignedTransaction(
            rawTransaction: signedEncoded,
            hash: signedHash,
            signature: txSignature
        )
    }
    
    func signMessage(_ message: String, withPrivateKey privateKeyData: Data) throws -> Data {
        let messageData = Data(message.utf8)
        
        // Ethereum signed message prefix
        let prefix = "\u{19}Ethereum Signed Message:\n\(messageData.count)"
        var prefixedMessage = Data(prefix.utf8)
        prefixedMessage.append(messageData)
        
        let messageHash = CryptoUtils.keccak256(prefixedMessage)
        
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: messageHash)
        
        return signature.rawRepresentation
    }
    
    private func weiFromEther(_ ether: Decimal) -> Data {
        let weiMultiplier = Decimal(sign: .plus, exponent: 18, significand: 1)
        let wei = ether * weiMultiplier
        let weiString = "\(wei)"
        
        if let weiInt = Int(weiString) {
            return CryptoUtils.intToData(weiInt)
        }
        return Data()
    }
}

// MARK: - Blockchain Communication Service

class BlockchainService {
    static let shared = BlockchainService()
    
    private let session = URLSession.shared
    
    // Ethereum JSON-RPC endpoint (configurable)
    var rpcEndpoint: URL
    
    // Chain ID (1 = mainnet, 5 = goerli, 11155111 = sepolia)
    var chainId: Int = 11155111 // Default to Sepolia testnet
    
    private init() {
        // Default to Infura Sepolia endpoint - replace with your API key
        self.rpcEndpoint = URL(string: "https://sepolia.infura.io/v3/YOUR_INFURA_API_KEY")!
    }
    
    func configure(rpcURL: String, chainId: Int) {
        if let url = URL(string: rpcURL) {
            self.rpcEndpoint = url
            self.chainId = chainId
        }
    }
    
    // MARK: - JSON-RPC Methods
    
    func getBalance(address: String) async throws -> String {
        let params: [Any] = [address, "latest"]
        let result: String = try await jsonRPCCall(method: "eth_getBalance", params: params)
        return hexToDecimalString(result)
    }
    
    func getTransactionCount(address: String) async throws -> Int {
        let params: [Any] = [address, "latest"]
        let result: String = try await jsonRPCCall(method: "eth_getTransactionCount", params: params)
        return hexToInt(result)
    }
    
    func getGasPrice() async throws -> String {
        let result: String = try await jsonRPCCall(method: "eth_gasPrice", params: [])
        return result
    }
    
    func estimateGas(from: String, to: String, value: String) async throws -> String {
        let txObject: [String: String] = [
            "from": from,
            "to": to,
            "value": value
        ]
        let params: [Any] = [txObject]
        let result: String = try await jsonRPCCall(method: "eth_estimateGas", params: params)
        return result
    }
    
    func sendRawTransaction(_ signedTxData: Data) async throws -> String {
        let hexTx = CryptoUtils.dataToHexString(signedTxData)
        let params: [Any] = [hexTx]
        let result: String = try await jsonRPCCall(method: "eth_sendRawTransaction", params: params)
        return result
    }
    
    func getTransactionReceipt(txHash: String) async throws -> [String: Any]? {
        let params: [Any] = [txHash]
        let result: [String: Any]? = try await jsonRPCCall(method: "eth_getTransactionReceipt", params: params)
        return result
    }
    
    func getBlockNumber() async throws -> Int {
        let result: String = try await jsonRPCCall(method: "eth_blockNumber", params: [])
        return hexToInt(result)
    }
    
    // MARK: - JSON-RPC Call
    
    private func jsonRPCCall<T>(method: String, params: [Any]) async throws -> T {
        var request = URLRequest(url: rpcEndpoint)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "method": method,
            "params": params,
            "id": 1
        ]
        
        request.httpBody = try JSONSerialization.data(withJSONObject: body)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw WalletError.networkError("Invalid response from blockchain node")
        }
        
        guard let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            throw WalletError.networkError("Invalid JSON response")
        }
        
        if let error = json["error"] as? [String: Any],
           let message = error["message"] as? String {
            throw WalletError.blockchainError(message)
        }
        
        guard let result = json["result"] as? T else {
            throw WalletError.networkError("Unexpected result type")
        }
        
        return result
    }
    
    // MARK: - Helpers
    
    private func hexToInt(_ hex: String) -> Int {
        var hexStr = hex
        if hexStr.hasPrefix("0x") {
            hexStr = String(hexStr.dropFirst(2))
        }
        return Int(hexStr, radix: 16) ?? 0
    }
    
    private func hexToDecimalString(_ hex: String) -> String {
        var hexStr = hex
        if hexStr.hasPrefix("0x") {
            hexStr = String(hexStr.dropFirst(2))
        }
        
        guard let value = UInt64(hexStr, radix: 16) else { return "0" }
        let ether = Double(value) / pow(10.0, 18.0)
        return String(format: "%.6f", ether)
    }
}

