    func createNewWallet(name: String) throws -> (wallet: Wallet, mnemonic: String) {
        let mnemonic = keyGenService.generateMnemonic()
        let keyPair = try keyGenService.generateKeyPairFromSeed(mnemonic)
        
        // Store private key in Keychain
        try keychainManager.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
        
        let wallet = Wallet(
            id: UUID(),
            name: name,
            address: keyPair.address,
            createdAt: Date()
        )
        
        wallets.append(wallet)
        if selectedWallet == nil {
            selectedWallet = wallet
        }
        saveWallets()
        
        return (wallet, mnemonic)
    }
    
    func importWallet(name: String, mnemonic: String) throws -> Wallet {
        let keyPair = try keyGenService.generateKeyPairFromSeed(mnemonic)
        
        try keychainManager.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
        
        let wallet = Wallet(
            id: UUID(),
            name: name,
            address: keyPair.address,
            createdAt: Date()
        )
        
        wallets.append(wallet)
        if selectedWallet == nil {
            selectedWallet = wallet
        }
        saveWallets()
        
        return wallet
    }
    
    func importWalletFromPrivateKey(name: String, privateKeyHex: String) throws -> Wallet {
        let privateKeyData = CryptoUtils.hexStringToData(privateKeyHex)
        
        // Derive public key and address
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let publicKeyData = privateKey.publicKey.rawRepresentation
        let hash = CryptoUtils.keccak256(publicKeyData)
        let addressBytes = hash.suffix(20)
        let address = CryptoUtils.dataToHexString(addressBytes)
        
        try keychainManager.storePrivateKey(privateKeyData, forAddress: address)
        
        let wallet = Wallet(
            id: UUID(),
            name: name,
            address: address,
            createdAt: Date()
        )
        
        wallets.append(wallet)
        if selectedWallet == nil {
            selectedWallet = wallet
        }
        saveWallets()
        
        return wallet
    }
    
    func deleteWallet(_ wallet: Wallet) throws {
        try keychainManager.deletePrivateKey(forAddress: wallet.address)
        wallets.removeAll { $0.id == wallet.id }
        
        if selectedWallet?.id == wallet.id {
            selectedWallet = wallets.first
        }
        saveWallets()
    }
    
    // MARK: - Balance & Transactions
    
    func refreshBalance() async {
        guard let wallet = selectedWallet else { return }
        
        await MainActor.run { isLoading = true }
        
        do {
            let balanceStr = try await blockchainService.getBalance(address: wallet.address)
            await MainActor.run {
                self.balance = balanceStr
                self.isLoading = false
            }
        } catch {
            await MainActor.run {
                self.error = .networkError(error.localizedDescription)
                self.isLoading = false
            }
        }
    }
    
    // MARK: - Send Transaction
    
    func sendTransaction(to: String, amount: Decimal) async throws -> String {
        guard let wallet = selectedWallet else {
            throw WalletError.noWalletSelected
        }
        
        await MainActor.run { isLoading = true }
        
        do {
            // Get nonce
            let nonce = try await blockchainService.getTransactionCount(address: wallet.address)
            
            // Get gas price
            let gasPriceHex = try await blockchainService.getGasPrice()
            var gasPriceStr = gasPriceHex
            if gasPriceStr.hasPrefix("0x") {
                gasPriceStr = String(gasPriceStr.dropFirst(2))
            }
            let gasPrice = Decimal(UInt64(gasPriceStr, radix: 16) ?? 21000000000)
            let fee = gasPrice / Decimal(sign: .plus, exponent: 18, significand: 1)
            
            // Create unsigned transaction
            let unsignedTx = UnsignedTransaction(
                to: to,
                amount: amount,
                fee: fee,
                nonce: nonce,
                chainId: blockchainService.chainId
            )
            
            // Get private key from keychain
            let privateKeyData = try keychainManager.retrievePrivateKey(forAddress: wallet.address)
            
            // Sign transaction
            let signedTx = try signingService.signTransaction(unsignedTx, withPrivateKey: privateKeyData)
            
            // Broadcast transaction
            let txHash = try await blockchainService.sendRawTransaction(signedTx.rawTransaction)
            
            // Store transaction locally
            let transaction = Transaction(
                id: UUID(),
                from: wallet.address,
                to: to,
                amount: amount,
                fee: fee,
                timestamp: Date(),
                hash: txHash,
                status: .pending,
                nonce: nonce
            )
            
            await MainActor.run {
                self.transactions.insert(transaction, at: 0)
                self.isLoading = false
                self.saveTransactions()
            }
            
            return txHash
            
        } catch {
            await MainActor.run {
                self.isLoading = false
                self.error = error as? WalletError ?? .transactionFailed(error.localizedDescription)
            }
            throw error
        }
    }
    
    // MARK: - Message Signing
    
    func signMessage(_ message: String) throws -> String {
        guard let wallet = selectedWallet else {
            throw WalletError.noWalletSelected
        }
        
        let privateKeyData = try keychainManager.retrievePrivateKey(forAddress: wallet.address)
        let signature = try signingService.signMessage(message, withPrivateKey: privateKeyData)
        
        return CryptoUtils.dataToHexString(signature)
    }
    
    // MARK: - Persistence
    
    private func saveWallets() {
        if let data = try? JSONEncoder().encode(wallets) {
            UserDefaults.standard.set(data, forKey: walletsKey)
        }
    }
    
    private func loadWallets() {
        if let data = UserDefaults.standard.data(forKey: walletsKey),
           let decoded = try? JSONDecoder().decode([Wallet].self, from: data) {
            wallets = decoded
            selectedWallet = decoded.first
        }
    }
    
    private func saveTransactions() {
        if let data = try? JSONEncoder().encode(transactions) {
            UserDefaults.standard.set(data, forKey: transactionsKey)
        }
    }
    
    private func loadTransactions() {
        if let data = UserDefaults.standard.data(forKey: transactionsKey),
           let decoded = try? JSONDecoder().decode([Transaction].self, from: data) {
            transactions = decoded
        }
    }
}

// MARK: - Errors

enum WalletError: Error, LocalizedError {
    case keychainError(String)
    case keyGenerationFailed(String)
    case transactionFailed(String)
    case networkError(String)
    case blockchainError(String)
    case noWalletSelected
    case invalidAddress
    case insufficientFunds
    case invalidMnemonic
    
    var errorDescription: String? {
        switch self {
        case .keychainError(let msg): return "Keychain error: \(msg)"
        case .keyGenerationFailed(let msg): return "Key generation failed: \(msg)"
        case .transactionFailed(let msg): return "Transaction failed: \(msg)"
        case .networkError(let msg): return "Network error: \(msg)"
        case .blockchainError(let msg): return "Blockchain error: \(msg)"
        case .noWalletSelected: return "No wallet selected"
        case .invalidAddress: return "Invalid address"
        case .insufficientFunds: return "Insufficient funds"
        case .invalidMnemonic: return "Invalid mnemonic phrase"
        }
    }
}

// MARK: - Biometric Authentication

import LocalAuthentication

class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    
    private init() {}
    
    var biometricType: LABiometryType {
        let context = LAContext()
        _ = context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil)
        return context.biometryType
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil)
    }
    
    func authenticate(reason: String) async throws -> Bool {
        let context = LAContext()
        context.localizedFallbackTitle = "Use Passcode"
        
        var authError: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &authError) else {
            // Fall back to passcode
            return try await authenticateWithPasscode(context: context, reason: reason)
        }
        
        return try await context.evaluatePolicy(
            .deviceOwnerAuthenticationWithBiometrics,
            localizedReason: reason
        )
    }
    
    private func authenticateWithPasscode(context: LAContext, reason: String) async throws -> Bool {
        return try await context.evaluatePolicy(
            .deviceOwnerAuthentication,
            localizedReason: reason
        )
    }
}

