                                .frame(maxWidth: .infinity)
                                .padding()
                                .background(walletName.isEmpty ? Color.gray : Color.blue)
                                .cornerRadius(12)
                        }
                        .disabled(walletName.isEmpty)
                    }
                    .padding()
                    
                } else if step == 1 {
                    // Show mnemonic
                    VStack(alignment: .leading, spacing: 16) {
                        Text("Recovery Phrase")
                            .font(.title2)
                            .fontWeight(.bold)
                        
                        Text("Write down these 12 words in order. This is the ONLY way to recover your wallet.")
                            .foregroundColor(.red)
                            .font(.callout)
                        
                        VStack(spacing: 8) {
                            let words = mnemonic.split(separator: " ")
                            ForEach(Array(words.enumerated()), id: \.offset) { index, word in
                                HStack {
                                    Text("\(index + 1).")
                                        .foregroundColor(.secondary)
                                        .frame(width: 30, alignment: .trailing)
                                    Text(String(word))
                                        .fontWeight(.medium)
                                        .font(.system(.body, design: .monospaced))
                                    Spacer()
                                }
                                .padding(.vertical, 4)
                                .padding(.horizontal)
                                .background(Color.gray.opacity(0.1))
                                .cornerRadius(8)
                            }
                        }
                        .padding(.vertical)
                        
                        Toggle("I have written down my recovery phrase", isOn: $mnemonicConfirmed)
                            .tint(.blue)
                        
                        Spacer()
                        
                        Button(action: { dismiss() }) {
                            Text("Done")
                                .font(.headline)
                                .foregroundColor(.white)
                                .frame(maxWidth: .infinity)
                                .padding()
                                .background(mnemonicConfirmed ? Color.blue : Color.gray)
                                .cornerRadius(12)
                        }
                        .disabled(!mnemonicConfirmed)
                    }
                    .padding()
                }
            }
            .navigationTitle(step == 0 ? "New Wallet" : "Backup")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
            .alert("Error", isPresented: $showError) {
                Button("OK") {}
            } message: {
                Text(errorMessage)
            }
        }
