                    TextField("Wallet Name", text: $walletName)
                        .textFieldStyle(RoundedBorderTextFieldStyle())
                    
                    if importType == 0 {
                        Text("Enter your 12-word recovery phrase")
                            .font(.caption)
                            .foregroundColor(.secondary)
                        
                        TextEditor(text: $mnemonic)
                            .frame(height: 120)
                            .border(Color.gray.opacity(0.3))
                            .cornerRadius(8)
                            .autocapitalization(.none)
                            .disableAutocorrection(true)
                    } else {
                        Text("Enter your private key (hex)")
                            .font(.caption)
                            .foregroundColor(.secondary)
                        
                        SecureField("0x...", text: $privateKey)
                            .textFieldStyle(RoundedBorderTextFieldStyle())
                            .autocapitalization(.none)
                            .disableAutocorrection(true)
                    }
                }
                .padding(.horizontal)
                
                Spacer()
                
                Button(action: importWallet) {
                    Text("Import Wallet")
                        .font(.headline)
                        .foregroundColor(.white)
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(canImport ? Color.blue : Color.gray)
                        .cornerRadius(12)
                }
                .disabled(!canImport)
                .padding(.horizontal)
                .padding(.bottom)
            }
            .navigationTitle("Import Wallet")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
            .alert("Error", isPresented: $showError) {
                Button("OK") {}
            } message: {
                Text(errorMessage)
            }
        }
    }
    
    private var canImport: Bool {
        !walletName.isEmpty && (importType == 0 ? !mnemonic.isEmpty : !privateKey.isEmpty)
    }
    
    private func importWallet() {
        do {
            if importType == 0 {
                _ = try walletManager.importWallet(name: walletName, mnemonic: mnemonic)
            } else {
                _ = try walletManager.importWalletFromPrivateKey(name: walletName, privateKeyHex: privateKey)
            }
            dismiss()
        } catch {
            errorMessage = error.localizedDescription
            showError = true
        }
    }
}

