struct SendView: View {
    @EnvironmentObject var walletManager: WalletManager
    @State private var recipientAddress = ""
    @State private var amount = ""
    @State private var showConfirmation = false
    @State private var showResult = false
    @State private var txHash = ""
    @State private var sendError: String?
    
    var body: some View {
        NavigationView {
            VStack(spacing: 24) {
                VStack(alignment: .leading, spacing: 8) {
                    Text("Recipient Address")
                        .font(.headline)
                    
                    TextField("0x...", text: $recipientAddress)
                        .textFieldStyle(RoundedBorderTextFieldStyle())
                        .autocapitalization(.none)
                        .disableAutocorrection(true)
                        .font(.system(.body, design: .monospaced))
                }
                
                VStack(alignment: .leading, spacing: 8) {
                    Text("Amount (ETH)")
                        .font(.headline)
                    
                    HStack {
                        TextField("0.0", text: $amount)
                            .textFieldStyle(RoundedBorderTextFieldStyle())
                            .keyboardType(.decimalPad)
                        
                        Button("Max") {
                            amount = walletManager.balance
                        }
                        .foregroundColor(.blue)
                    }
                    
                    Text("Balance: \(walletManager.balance) ETH")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                
                Spacer()
                
                if let error = sendError {
                    Text(error)
                        .foregroundColor(.red)
                        .font(.callout)
                }
                
                Button(action: { showConfirmation = true }) {
                    Text("Send")
                        .font(.headline)
                        .foregroundColor(.white)
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(canSend ? Color.blue : Color.gray)
                        .cornerRadius(12)
                }
                .disabled(!canSend)
            }
            .padding()
            .navigationTitle("Send")
            .alert("Confirm Transaction", isPresented: $showConfirmation) {
                Button("Cancel", role: .cancel) {}
                Button("Confirm") {
                    sendTransaction()
                }
            } message: {
                Text("Send \(amount) ETH to \(truncateAddress(recipientAddress))?")
            }
            .alert("Transaction Sent", isPresented: $showResult) {
                Button("OK") {
                    recipientAddress = ""
                    amount = ""
                }
            } message: {
                Text("Transaction hash:\n\(txHash)")
            }
        }
    }
    
    private var canSend: Bool {
        !recipientAddress.isEmpty && !amount.isEmpty &&
        recipientAddress.hasPrefix("0x") && recipientAddress.count == 42 &&
        Decimal(string: amount) != nil && Decimal(string: amount)! > 0
    }
    
    private func sendTransaction() {
        Task {
            do {
                let authenticated = try await BiometricAuthManager.shared.authenticate(
                    reason: "Authenticate to send transaction"
                )
                
                guard authenticated else {
                    await MainActor.run { sendError = "Authentication failed" }
                    return
                }
                
                guard let amountDecimal = Decimal(string: amount) else { return }
                
                let hash = try await walletManager.sendTransaction(
                    to: recipientAddress,
                    amount: amountDecimal
                )
                
                await MainActor.run {
                    txHash = hash
                    showResult = true
                    sendError = nil
                }
            } catch {
                await MainActor.run {
                    sendError = error.localizedDescription
                }
            }
        }
    }
    
    private func truncateAddress(_ address: String) -> String {
        guard address.count > 10 else { return address }
        return "\(address.prefix(6))...\(address.suffix(4))"
    }
}

