                        .contentShape(Rectangle())
                        .onTapGesture {
                            walletManager.selectedWallet = wallet
                            Task { await walletManager.refreshBalance() }
                        }
                        .swipeActions(edge: .trailing, allowsFullSwipe: false) {
                            Button(role: .destructive) {
                                walletToDelete = wallet
                                showDeleteAlert = true
                            } label: {
                                Label("Delete", systemImage: "trash")
                            }
                        }
                    }
                    
                    Button(action: { showCreateWallet = true }) {
                        Label("Create New Wallet", systemImage: "plus.circle.fill")
                    }
                    
                    Button(action: { showImportWallet = true }) {
                        Label("Import Wallet", systemImage: "arrow.down.circle.fill")
                    }
                }
                
                // Network Configuration
                Section("Network") {
                    VStack(alignment: .leading, spacing: 4) {
                        Text("Current Network")
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Text(networkName)
                            .font(.headline)
                    }
                    
                    NavigationLink("Configure RPC") {
                        NetworkConfigView(rpcURL: $rpcURL, networkName: $networkName)
                    }
                }
                
                // Security
                Section("Security") {
                    HStack {
                        Label("Biometric Auth", systemImage: "faceid")
                        Spacer()
                        Text(BiometricAuthManager.shared.isBiometricAvailable ? "Enabled" : "Not Available")
                            .foregroundColor(.secondary)
                    }
                }
                
                // About
                Section("About") {
                    HStack {
                        Text("Version")
                        Spacer()
                        Text("1.0.0 MVP")
                            .foregroundColor(.secondary)
                    }
                    
                    HStack {
                        Text("Chain ID")
                        Spacer()
                        Text("\(BlockchainService.shared.chainId)")
                            .foregroundColor(.secondary)
                    }
                }
            }
            .navigationTitle("Settings")
            .sheet(isPresented: $showCreateWallet) {
                CreateWalletView()
            }
            .sheet(isPresented: $showImportWallet) {
                ImportWalletView()
            }
            .alert("Delete Wallet", isPresented: $showDeleteAlert) {
                Button("Cancel", role: .cancel) {}
                Button("Delete", role: .destructive)